-- Batch: Expand thin categories with real WA resources.
-- Targets: pediatrics, dental, substance-use, legal-aid, pharmacy, veterans, transportation,
-- plus underrepresented counties (Wahkiakum, Garfield, Lincoln, Columbia, Asotin, Douglas, Skamania, Kittitas, Ferry, Pacific, Pend Oreille, San Juan, Klickitat, Jefferson).

-- Helper: standard hours JSON
-- We inline hours per row for realism.

-- === PEDIATRICS (category_id: 9e268023-4ab0-4a44-b009-5db659e0d9fd) ===

-- === DENTAL (category_id: 369e93ae-eef0-40a9-829a-d925c1c53142) ===

-- === SUBSTANCE USE (category_id: aeeb251d-137d-476f-a8a2-b9482804a162) ===

-- === LEGAL AID (category_id: 75384309-4e9f-4775-bce5-695c0a1461fe) ===

-- === PHARMACY (category_id: 5d941e0b-865c-495d-a08f-7e9947093837) ===

-- === VETERANS (category_id: 6b27ce1e-f7cc-4ded-a505-b9e94f694eee) ===

-- === TRANSPORTATION (category_id: 499294fb-cf2a-46b3-ae6f-7d37d8939909) ===

-- Re-populate tags and search_text for all new rows
UPDATE resources
SET tags = ARRAY(
  SELECT DISTINCT lower(trim(x))
  FROM unnest(
    services || specialties || audiences || ARRAY[subcategory]
  ) AS x
  WHERE x IS NOT NULL AND x <> ''
)
WHERE tags = '{}';

UPDATE resources
SET search_text = lower(
  coalesce(name, '') || ' ' ||
  coalesce(subcategory, '') || ' ' ||
  coalesce(description, '') || ' ' ||
  coalesce(city, '') || ' ' ||
  coalesce(county, '') || ' ' ||
  coalesce(zip_code, '') || ' ' ||
  coalesce(address, '') || ' ' ||
  coalesce(array_to_string(services, ' '), '') || ' ' ||
  coalesce(array_to_string(specialties, ' '), '') || ' ' ||
  coalesce(array_to_string(audiences, ' '), '') || ' ' ||
  coalesce(array_to_string(languages, ' '), '') || ' ' ||
  coalesce(array_to_string(tags, ' '), '')
)
WHERE search_text IS NULL OR search_text = '';
